#include <vector>

bool solve(std::vector<long long> nums) {
    int n = nums.size();
    for (int p = 1; p <= n - 3; ++p) {
        for (int q = p + 1; q <= n - 2; ++q) {
            // Check first part: 0 to p is strictly increasing
            bool first = true;
            for (int i = 0; i < p; ++i) {
                if (nums[i] >= nums[i + 1]) {
                    first = false;
                    break;
                }
            }
            if (!first) continue;

            // Check second part: p to q is strictly decreasing
            bool second = true;
            for (int i = p; i < q; ++i) {
                if (nums[i] <= nums[i + 1]) {
                    second = false;
                    break;
                }
            }
            if (!second) continue;

            // Check third part: q to end is strictly increasing
            bool third = true;
            for (int i = q; i < n - 1; ++i) {
                if (nums[i] >= nums[i + 1]) {
                    third = false;
                    break;
                }
            }
            if (third) return true;
        }
    }
    return false;
}

